import React, { useState, useEffect } from "react"
import Fade from "./animations/Fade"
import { Carousel } from "react-bootstrap"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"
import Modal from "./modal"
import "../styles/selected-projects.scss"
import { GatsbyImage } from "gatsby-plugin-image"
import useAllImages from "../hooks/useAllImages"
import VideoPlayer from "./atoms/VideoPlayer"


const SelectedProjects = () => {
  const { language } = useLanguage();
  const [activeIndex, setActiveIndex] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  const [isTouchDevice, setIsTouchDevice] = useState(false);
  const [openModal, setOpenModal] = useState(false);
  const [id, setId] = useState(0);
  const carouselRef = React.useRef(null);
  const { findImage } = useAllImages();

  // Caption Toggle State
  const [captionToggle, setCaptionToggle] = useState(null);

  // Sync touch state with default caption visibility
  useEffect(() => {
    setCaptionToggle(isTouchDevice ? true : null);
  }, [isTouchDevice]);

  // Handle outside clicks to force-hide caption, distinguishing tap from scroll
  useEffect(() => {
    let isScrolling = false;

    const handleTouchMove = () => {
      isScrolling = true;
    };

    const handleClickOutside = (event) => {
      // If it was a scroll (touchmove fired), don't hide the caption
      if (event.type === 'touchend' && isScrolling) {
        isScrolling = false;
        return;
      }
      isScrolling = false;

      if (carouselRef.current && !carouselRef.current.contains(event.target)) {
        setCaptionToggle(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('touchmove', handleTouchMove);
    document.addEventListener('touchend', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('touchmove', handleTouchMove);
      document.removeEventListener('touchend', handleClickOutside);
    };
  }, []);


  // Get carousel items from data with translated content
  const carouselItems = data.projectsCarouselItems.map(item => ({
    ...item,
    // Resolve media: if it's a string and an image, use findImage
    media: item.type === 'image' && typeof item.media === 'string'
      ? findImage(item.media)
      : item.media,
    title: getText(item.title, language),
    subtitle: getText(item.subtitle, language),
    description: getText(item.description, language),
    buttons: item.buttons.map(btn => ({
      ...btn,
      text: getText(btn.text, language)
    })),
    // Resolve mediaItems for modals
    mediaItems: item.mediaItems ? item.mediaItems.map(mi => ({
      ...mi,
      src: mi.type === 'image' && typeof mi.src === 'string'
        ? findImage(mi.src)
        : mi.src
    })) : item.mediaItems
  }));

  // Detect touch and mobile devices
  useEffect(() => {
    const checkDevice = () => {
      setIsMobile(window.innerWidth <= 768);
      const touch = ('ontouchstart' in window) || (navigator.maxTouchPoints > 0) || (navigator.msMaxTouchPoints > 0);
      setIsTouchDevice(touch);
    };

    checkDevice();
    try {
      window.addEventListener('resize', checkDevice);
    } catch (error) {
      console.warn('Error adding resize listener:', error);
    }

    return () => {
      try {
        window.removeEventListener('resize', checkDevice);
      } catch (error) {
        console.warn('Error removing resize listener:', error);
      }
    };
  }, []);

  // Handle carousel selection
  const handleCarouselSelect = (selectedIndex) => {
    try {
      setActiveIndex(selectedIndex);
      setCaptionToggle(isTouchDevice ? true : null);
    } catch (error) {
      console.error('Error in projects carousel selection:', error);
    }
  };
  // Navigation handlers for modal (infinite loop)
  const handlePrevious = () => {
    setId((id - 1 + carouselItems.length) % carouselItems.length);
  };

  const handleNext = () => {
    setId((id + 1) % carouselItems.length);
  };

  return (
    <div className="section" id="projects">
      <div className="container">
        <Fade bottom cascade distance="20px">
          <h1>{getText(data.sections.projects, language)}</h1>
          <h3 className="section-subheading">
            {getText(data.projectsSubtitle, language)}
          </h3>
        </Fade>
        <div className="project-wrapper" ref={carouselRef}>
          <Carousel
            className="masterCarousel"
            activeIndex={activeIndex}
            onSelect={handleCarouselSelect}
            touch={true}
            pause={isTouchDevice ? false : 'hover'}
            interval={3000}
            indicators={!isMobile} // Hide indicators on mobile
            controls={true}
            keyboard={false}
            slide={true}
            wrap={true}
            variant="dark"
          >
            {carouselItems.map((item, index) => (
              <Carousel.Item key={index}>
                <div 
                  style={{ width: '100%', height: '100%', cursor: 'pointer' }}
                  onClick={() => setCaptionToggle(prev => prev === null ? true : prev === true ? false : true)}
                >
                  {item.type === 'video' ? (
                    <VideoPlayer
                      mp4={item.media}
                      webm={item.mediaWebm}
                      className="d-block w-100"
                      muted
                      loop
                    />
                  ) : item.media && typeof item.media === 'object' ? (
                    <GatsbyImage
                      image={item.media}
                      alt={item.title}
                      className="d-block w-100"
                    />
                  ) : (
                    <div className="d-block w-100 bg-secondary" style={{ aspectRatio: '16/9' }} />
                  )}
                  <Carousel.Caption className={`carouselCaption ${item.captionVariant === 'light' ? 'caption-light' : ''} ${captionToggle === true ? 'force-show' : ''} ${captionToggle === false ? 'force-hide' : ''}`}>
                    <h3>{item.title}</h3>
                    <h4>{item.subtitle}</h4>
                    <p dangerouslySetInnerHTML={{ __html: item.description }}></p>
                    {item.buttons.map((button, buttonIndex) => (
                      <button
                        key={buttonIndex}
                        onClick={(e) => {
                          e.stopPropagation();
                          if (button.isModal) {
                            setId(index);
                            setOpenModal(true);
                          } else {
                            window.open(button.url, "_blank", "noopener,noreferrer");
                          }
                        }}
                        type="button"
                        className="btn"
                      >
                        {button.text}
                      </button>
                    ))}
                  </Carousel.Caption>
                </div>
              </Carousel.Item>
            ))}
          </Carousel>
          {openModal && <Modal
            closeModal={setOpenModal}
            id={id}
            type="selectedProject"
            totalItems={carouselItems.length}
            onPrevious={handlePrevious}
            onNext={handleNext}
          />}
        </div>
      </div>
    </div>
  )
}

export default SelectedProjects
