import React, { useRef, useEffect, useState } from "react";

/**
 * VideoPlayer — shared video component with:
 * - Dual <source> (WebM preferred, MP4 fallback)
 * - IntersectionObserver autoplay: plays only when visible, pauses when not
 * - preload="metadata": fetches dimensions/duration only
 * - Error fallback with optional custom content
 *
 * Props:
 *   mp4/webm     {string}  Video source URLs
 *   autoPlay     {bool}    Autoplay when visible (default: true)
 *   muted        {bool}    Mute audio (default: true, required for autoplay)
 *   loop         {bool}    Loop playback (default: true)
 *   className    {string}  CSS classes
 *   style        {object}  Inline styles
 *   controls     {bool}    Show browser controls (default: false)
 *   poster       {string}  Poster frame URL
 *   onLoaded     {func}    Callback on video data load
 *   videoRef     {ref}     External ref to access the <video> element
 *   fallback     {node}    Custom error fallback
 *   threshold    {number}  IO visibility threshold (default: 0.3)
 */
const VideoPlayer = ({
  mp4,
  webm,
  autoPlay = true,
  muted = true,
  loop = true,
  className = "",
  style = {},
  controls = false,
  poster,
  onLoaded,
  videoRef: externalRef,
  fallback,
  threshold = 0.3,
  ...rest
}) => {
  const internalRef = useRef(null);
  const videoRef = externalRef || internalRef;
  const [hasError, setHasError] = useState(false);

  // Autoplay when visible, pause when not
  useEffect(() => {
    if (!autoPlay) return;
    const video = videoRef.current;
    if (!video) return;

    const safePlay = () => {
      video.muted = true;
      video.play().catch(() => {});
    };

    const observer = new IntersectionObserver(
      ([entry]) => { entry.isIntersecting ? safePlay() : video.pause(); },
      { threshold }
    );
    observer.observe(video);
    return () => observer.disconnect();
  }, [autoPlay, threshold, videoRef]);

  // Reload when source props change (browser ignores <source> swaps without .load())
  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const handleLoaded = () => {
      if (autoPlay) {
        video.muted = true;
        video.play().catch(() => {});
      }
    };

    video.addEventListener('loadeddata', handleLoaded, { once: true });
    video.load();

    return () => video.removeEventListener('loadeddata', handleLoaded);
  }, [mp4, webm]); // eslint-disable-line react-hooks/exhaustive-deps

  if (hasError) {
    return fallback || (
      <div
        className={className}
        style={{
          display: "flex", alignItems: "center", justifyContent: "center",
          backgroundColor: "var(--bg-secondary, #e9ecef)", aspectRatio: "16/9",
          borderRadius: "8px", color: "var(--text-dark-secondary, #6c757d)",
          fontSize: "0.85rem", textAlign: "center", padding: "16px",
          ...style,
        }}
      >
        <span>🎬 Video preview unavailable</span>
      </div>
    );
  }

  return (
    <video
      ref={videoRef}
      className={className}
      style={style}
      muted={muted}
      loop={loop}
      playsInline
      preload="metadata"
      controls={controls}
      poster={poster}
      disablePictureInPicture
      onLoadedData={onLoaded}
      onError={() => setHasError(true)}
      {...rest}
    >
      {webm && <source src={webm} type="video/webm" />}
      {mp4 && <source src={mp4} type="video/mp4" />}
    </video>
  );
};

export default VideoPlayer;
